99	  models.UDFTable.findAll({
100	    where: {
101	      container_id: 'rfq'
102	    }
103	  })
104	  .then(async (data) => {
105	      if (data) {
106	        //if UDFElement_id_fk is 0 it means that we will run that on constructor
107	        //if UDFTable_primary_id is 0 and UDFTable_associate_type is 0 then that is the primary table for the associations
108	        await data.forEach(element => {
109	          if (element.UDFTable_primary_id == '0') {
110	            primaryTables.push(element)
111	          } else {
112	            jointTables.push(element)
113	          }
114	        });
115	        //define modules associations
116	        for (var i = 0; jointTables.length > i; i++) {
117	          for (var j = 0; primaryTables.length > j; j++) {
118	            if (jointTables[i].UDFTable_foreignKey != '0' && jointTables[i].UDFTable_targetKey != '0' && parseInt(primaryTables[j].UDFTable_id) === parseInt(jointTables[i].UDFTable_primary_id)) {
119	              models[primaryTables[j].UDFTable_name][jointTables[i].UDFTable_associate_type](models[jointTables[i].UDFTable_name], { foreignKey: jointTables[i].UDFTable_foreignKey, sourceKey: jointTables[i].UDFTable_targetKey })
120	            } else if (jointTables[i].UDFTable_foreignKey != '0' && parseInt(primaryTables[j].UDFTable_id) === parseInt(jointTables[i].UDFTable_primary_id)) {
121	              /* Checking if the jointTables[i] has a nickname, if it does then it will add the nickname to the
122	              association. the nickname will work only with belongs to for now. */
123	              if (jointTables[i].nickname) {
124	                models[primaryTables[j].UDFTable_name][jointTables[i].UDFTable_associate_type](models[jointTables[i].UDFTable_name], { foreignKey: jointTables[i].UDFTable_foreignKey, as: jointTables[i].nickname })
125	              } else {
126	                models[primaryTables[j].UDFTable_name][jointTables[i].UDFTable_associate_type](models[jointTables[i].UDFTable_name], { foreignKey: jointTables[i].UDFTable_foreignKey })
127	              }
128	            }
129	          }
130	        };
131	      } else {
132	      }
133	
134	  })
135	
136	  // Add hooks for automatic audit logging
137	  for (const modelName in models) {
138	    const model = models[modelName];
139	    if (model.name === 'AuditLog') continue; // Don't log the logger
140	
141	    model.addHook('afterCreate', (instance, options) => {
142	      try {
143	        const changedData = instance.dataValues;
144	        const pkName = model.primaryKeyAttribute;
145	        const pkValue = instance[pkName];
146	        AuditService.log(models, 'Create', model, pkValue, JSON.stringify(changedData), null);
147	      } catch (e) {
148	        console.error("Error in afterCreate hook for " + model.name, e)
149	      }
150	    });
151	
152	    model.addHook('afterUpdate', (instance, options) => {
153	       try {
154	        const changedData = instance.dataValues;
155	        const previousData = instance._previousDataValues;
156	        const pkName = model.primaryKeyAttribute;
157	        const pkValue = options.ref_id || instance[pkName];
158	        AuditService.log(models, 'Update', model, pkValue, JSON.stringify(changedData), JSON.stringify(previousData));
159	      } catch (e) {
160	        console.error("Error in afterUpdate hook for " + model.name, e)
161	      }
162	    });
163	
164	    model.addHook('afterBulkCreate', (instances, options) => {
165	      try {
166	        const pkName = model.primaryKeyAttribute;
167	        for(const instance of instances) {
168	          const changedData = instance.dataValues;
169	          const pkValue = instance[pkName];
170	          AuditService.log(models, 'Create', model, pkValue, JSON.stringify(changedData), null);
171	        }
172	      } catch (e) {
173	        console.error("Error in afterBulkCreate hook for " + model.name, e)
174	      }
175	    });
176	  };
177	
178	  return models
179	}
180	module.exports = initModels;
181	module.exports.initModels = initModels;
182	module.exports.default = initModels;
