358	ProdTracking.getFactoryProdOrderList = async (req, result) => {
359	  try {
360	    const decoded = decodeAuthUser(req);
361	    const baseWhere = {
362	      prodReferenceNo: { [Op.notILike]: '%COS' }
363	    };
364	    const factoryId = req.query.factoryId;
365	    let vendorExternal = null;
366	
367	    const startRow =
368	      req.query.startRow !== undefined && req.query.startRow !== null
369	        ? Math.max(0, Number(req.query.startRow))
370	        : 0;
371	    let endRow =
372	      req.query.endRow !== undefined && req.query.endRow !== null
373	        ? Number(req.query.endRow)
374	        : startRow + 10000;
375	    if (Number.isNaN(endRow) || endRow < startRow) {
376	      endRow = startRow + 10000;
377	    }
378	    const MAX_PAGE = 50000;
379	    let limit = endRow - startRow;
380	    if (limit <= 0) {
381	      limit = 100;
382	    }
383	    limit = Math.min(limit, MAX_PAGE);
384	
385	    let filters = {};
386	    try {
387	      filters =
388	        req.query.filterModel && String(req.query.filterModel).trim() !== ''
389	          ? JSON.parse(req.query.filterModel)
390	          : {};
391	    } catch (e) {
392	      filters = {};
393	    }
394	
395	    if (decoded.role === 'vendor') {
396	      vendorExternal = await sql.externalVendor.findOne({
397	        where: sql.sequelize.where(
398	          sql.sequelize.fn('lower', sql.sequelize.col('email')),
399	          (decoded.email || '').toLowerCase()
400	        )
401	      });
402	      if (!vendorExternal) {
403	        return result(null, { rows: [], totalCount: 0 });
404	      }
405	      baseWhere.vendorCode = vendorExternal.vendorCode;
406	    }
407	
408	    const factoryIdMissing =
409	      factoryId === undefined || factoryId === null || String(factoryId).trim() === '';
410	    if (factoryIdMissing) {
411	      return result(null, { rows: [], totalCount: 0 });
412	    }
413	
414	    const codes = await getVendorCodesForFactoryId(factoryId);
415	
416	    if (decoded.role === 'vendor') {
417	      if (decoded.factory_id != null && String(factoryId) !== String(decoded.factory_id)) {
418	        return result(null, { rows: [], totalCount: 0 });
419	      }
420	      if (codes && codes.length > 0 && !codes.includes(vendorExternal.vendorCode)) {
421	        return result(null, { rows: [], totalCount: 0 });
422	      }
423	      // Vendor: always scope by their Cold Lion vendorCode. If core vendor↔email link
424	      // returns no codes (data drift), still return their POs when factory matches JWT.
425	    } else {
426	      if (!codes || codes.length === 0) {
427	        return result(null, { rows: [], totalCount: 0 });
428	      }
429	      baseWhere.vendorCode = { [Op.in]: codes };
430	    }
431	
432	    const filterWhere = buildFactoryProdOrderFilterWhere(filters);
433	    let where = baseWhere;
434	    if (filterWhere) {
435	      where = { [Op.and]: [baseWhere, filterWhere] };
436	    }
437	
438	    const totalCount = await sql.ProdOrderHeader.count({ where, distinct: true, col: 'id' });
439	
440	    const rows = await sql.ProdOrderHeader.findAll({
441	      where,
442	      attributes: [
443	        'id',
444	        'prodOrderNo',
445	        'prodReferenceNo',
446	        'vendorCode',
447	        'material_arrival_date',
448	        'mass_prod_start_date',
449	        'assembly_start_date',
450	        'actual_prod_complete',
451	        'packing_start_date',
452	        'qc_inspection_date',
453	        'actual_etd'
454	      ],
455	      order: [['dueDate', 'DESC']],
456	      limit,
457	      offset: startRow
458	    });
459	
460	    result(null, {
461	      rows: rows.map((r) => r.get({ plain: true })),
462	      totalCount
463	    });
464	  } catch (err) {
465	    console.error('getFactoryProdOrderList:', err);
466	    result(err, null);
467	  }
468	};
