23	// Translate one AG Grid filter definition into a Sequelize condition.
24	// Mirrors the buildCondition logic used in lic.model.js.
25	const buildCondition = (filterDef) => {
26	  if (!filterDef) return null;
27	
28	  if (filterDef.filterType === 'date') {
29	    const { type, dateFrom, dateTo } = filterDef;
30	    if (!dateFrom) return null;
31	    const startOfDay = new Date(dateFrom);
32	    startOfDay.setHours(0, 0, 0, 0);
33	    const endOfDay = new Date(startOfDay);
34	    endOfDay.setHours(23, 59, 59, 999);
35	    switch (type) {
36	      case 'equals': return { [Op.between]: [startOfDay, endOfDay] };
37	      case 'notEqual': return { [Op.notBetween]: [startOfDay, endOfDay] };
38	      case 'lessThan': return { [Op.lt]: startOfDay };
39	      case 'greaterThan': return { [Op.gt]: startOfDay };
40	      case 'inRange': {
41	        if (!dateTo) return null;
42	        const rangeEnd = new Date(dateTo);
43	        rangeEnd.setHours(23, 59, 59, 999);
44	        return { [Op.between]: [startOfDay, rangeEnd] };
45	      }
46	      default: return null;
47	    }
48	  }
49	
50	  if (filterDef.filterType === 'number') {
51	    const n = filterDef.filter;
52	    switch (filterDef.type) {
53	      case 'equals': return { [Op.eq]: n };
54	      case 'notEqual': return { [Op.ne]: n };
55	      case 'lessThan': return { [Op.lt]: n };
56	      case 'lessThanOrEqual': return { [Op.lte]: n };
57	      case 'greaterThan': return { [Op.gt]: n };
58	      case 'greaterThanOrEqual': return { [Op.gte]: n };
59	      case 'inRange': return { [Op.between]: [n, filterDef.filterTo] };
60	      default: return null;
61	    }
62	  }
63	
64	  // default: text
65	  const value = typeof filterDef.filter === 'string' ? filterDef.filter : '';
66	  switch (filterDef.type) {
67	    case 'contains': return { [Op.iLike]: `%${value}%` };
68	    case 'notContains': return { [Op.notILike]: `%${value}%` };
69	    case 'equals': return { [Op.eq]: filterDef.filter };
70	    case 'notEqual': return { [Op.ne]: filterDef.filter };
71	    case 'startsWith': return { [Op.iLike]: `${value}%` };
72	    case 'endsWith': return { [Op.iLike]: `%${value}` };
73	    case 'blank': return { [Op.or]: [{ [Op.eq]: null }, { [Op.eq]: '' }] };
74	    case 'notBlank': return { [Op.and]: [{ [Op.ne]: null }, { [Op.ne]: '' }] };
75	    default: return null;
76	  }
77	};
